    17→// Upload a base64 image frame to R2 and return the CDN URL
    18→// The Polsia OpenAI proxy only supports HTTP URLs for vision, NOT base64 data URIs
    19→async function uploadFrameToR2(base64Data, index) {
    20→  try {
    21→    // Strip data URI prefix if present
    22→    const raw = base64Data.replace(/^data:image\/\w+;base64,/, '');
    23→    const buffer = Buffer.from(raw, 'base64');
    24→
    25→    const formData = new FormData();
    26→    formData.append('file', buffer, {
    27→      filename: `video-frame-${Date.now()}-${index}.jpg`,
    28→      contentType: 'image/jpeg'
    29→    });
    30→
    31→    const res = await fetch('https://polsia.com/api/proxy/r2/upload', {
    32→      method: 'POST',
    33→      headers: {
    34→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
    35→        ...formData.getHeaders()
    36→      },
    37→      body: formData
    38→    });
    39→
    40→    const result = await res.json();
    41→    if (!result.success) {
    42→      console.error(`R2 frame upload failed (frame ${index}):`, result.error);
    43→      return null;
    44→    }
    45→    return result.file.url;
    46→  } catch (err) {
    47→    console.error(`R2 frame upload error (frame ${index}):`, err.message);
    48→    return null;
    49→  }
    50→}
