   551→// Select evenly-spaced key frames from a larger set
   552→function selectKeyFrames(frames, count) {
   553→  const result = [];
   554→  const step = (frames.length - 1) / (count - 1);
   555→  for (let i = 0; i < count; i++) {
   556→    result.push(frames[Math.round(i * step)]);
   557→  }
   558→  return result;
   559→}
