   904→// AI interviewer conducts a conversational interview turn
   905→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
   906→  // Send last 12 turns for better context on follow-ups
   907→  const recentConvo = conversation.slice(-12);
   908→  const convoText = recentConvo.map(turn => {
   909→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
   910→    return `CANDIDATE: ${turn.text}`;
   911→  }).join('\n\n');
   912→
   913→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
   914→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
   915→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
   916→  const nextPlannedQuestion = remainingQuestions.length > 0
   917→    ? remainingQuestions[0].question_text
   918→    : null;
   919→
   920→  // Count consecutive follow-ups on the current topic
   921→  let consecutiveFollowUps = 0;
   922→  for (let i = conversation.length - 1; i >= 0; i--) {
   923→    const t = conversation[i];
   924→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
   925→      consecutiveFollowUps++;
   926→    } else if (t.role === 'interviewer' && t.action === 'transition') {
   927→      break;
   928→    } else if (t.role === 'candidate') {
   929→      continue; // skip candidate turns when counting
   930→    }
   931→  }
   932→
   933→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
   934→
   935→CONVERSATION SO FAR:
   936→${convoText}
   937→
   938→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
   939→
   940→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
   941→
   942→YOUR TASK: Act like a real interviewer. After the candidate answers:
   943→
   944→1. **FOLLOW UP** if the answer is:
   945→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
   946→   - Missing specifics (no metrics, no concrete examples, no details about their role)
   947→   - Interesting but unexplored (they mentioned something worth digging into)
   948→   - Missing the "so what" (they described what happened but not the impact/result)
   949→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
   950→
   951→2. **TRANSITION** to the next planned question when:
   952→   - The candidate gave a thorough, specific answer with concrete examples
   953→   - You've already asked 2-3 follow-ups and have sufficient depth
   954→   - The candidate clearly has nothing more to add on this topic
   955→
   956→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
   957→
   958→React naturally to their answer (1-2 sentences — acknowledge what they said, show genuine interest), then ask your question.
   959→
   960→Return JSON: {"reaction":"1-2 sentence natural reaction to their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
   961→
   962→  const result = await chat(prompt, {
   963→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
   964→    maxTokens: 1024,
   965→    subscriptionId: options.subscriptionId
   966→  });
   967→
   968→  try {
   969→    return JSON.parse(result);
   970→  } catch (e) {
   971→    const match = result.match(/\{[\s\S]*\}/);
   972→    if (match) return JSON.parse(match[0]);
   973→    throw new Error('Failed to generate interview turn');
   974→  }
