  1133→    }
  1134→
  1135→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1136→
  1137→    // Use provider service with automatic fallback
  1138→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1139→      voice,
