     1→/**
     2→ * OpenAI Token Budget Service
     3→ *
     4→ * Tracks OpenAI token usage across all modalities (LLM, TTS, ASR, Vision, Embedding).
     5→ * When daily budget (100K tokens) is exhausted, signals the AI provider to skip OpenAI
     6→ * and route directly to NIM providers.
     7→ *
     8→ * Token estimation:
     9→ * - LLM: uses response.usage.total_tokens when available, estimates from text length otherwise
    10→ * - TTS: ~1 token per 4 characters of input text
    11→ * - ASR: ~1 token per second of audio (Whisper pricing model)
    12→ * - Vision: ~85 tokens per image + prompt tokens
    13→ * - Embedding: ~1 token per 4 characters
    14→ */
    15→
    16→const DAILY_BUDGET = parseInt(process.env.OPENAI_DAILY_TOKEN_BUDGET, 10) || 100000;
    17→
    18→class TokenBudgetService {
    19→  constructor() {
    20→    this.dailyBudget = DAILY_BUDGET;
    21→    this.tokensUsed = 0;
    22→    this.budgetExhausted = false;
    23→    this.currentDay = this._getUTCDay();
    24→    this.history = [];         // Last 7 days of usage
    25→    this.modalityBreakdown = { // Per-modality tracking
    26→      llm: 0,
    27→      tts: 0,
    28→      asr: 0,
    29→      vision: 0,
    30→      embedding: 0,
    31→      other: 0,
    32→    };
    33→    this.providerBreakdown = { // Per-provider tracking (OpenAI vs NIM)
    34→      openai: 0,
    35→      nim: 0,
    36→      other: 0,
    37→    };
    38→    this.exhaustedAt = null;   // Timestamp when budget was exhausted
    39→    this.resetAt = null;       // Next reset time
    40→
    41→    this._updateResetTime();
    42→    this._startMidnightReset();
    43→
    44→    console.log(`[token-budget] Initialized. Daily budget: ${this.dailyBudget.toLocaleString()} tokens`);
    45→  }
    46→
    47→  _getUTCDay() {
    48→    const now = new Date();
    49→    return `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, '0')}-${String(now.getUTCDate()).padStart(2, '0')}`;
    50→  }
    51→
    52→  _updateResetTime() {
    53→    const now = new Date();
    54→    const tomorrow = new Date(Date.UTC(
    55→      now.getUTCFullYear(),
    56→      now.getUTCMonth(),
    57→      now.getUTCDate() + 1,
    58→      0, 0, 0, 0
    59→    ));
    60→    this.resetAt = tomorrow.toISOString();
    61→  }
    62→
    63→  _startMidnightReset() {
    64→    // Check every 60 seconds if the day has changed
    65→    this._resetInterval = setInterval(() => {
    66→      const today = this._getUTCDay();
    67→      if (today !== this.currentDay) {
    68→        this._performReset(today);
    69→      }
    70→    }, 60 * 1000);
    71→  }
    72→
    73→  _performReset(newDay) {
    74→    // Save yesterday's usage to history
    75→    this.history.push({
    76→      date: this.currentDay,
    77→      tokensUsed: this.tokensUsed,
    78→      budget: this.dailyBudget,
    79→      breakdown: { ...this.modalityBreakdown },
    80→      providerBreakdown: { ...this.providerBreakdown },
    81→      exhaustedAt: this.exhaustedAt,
    82→    });
    83→
    84→    // Keep only last 7 days
    85→    if (this.history.length > 7) {
    86→      this.history.shift();
    87→    }
    88→
    89→    // Reset counters
    90→    const wasExhausted = this.budgetExhausted;
    91→    this.tokensUsed = 0;
    92→    this.budgetExhausted = false;
    93→    this.exhaustedAt = null;
    94→    this.currentDay = newDay;
    95→    this.modalityBreakdown = { llm: 0, tts: 0, asr: 0, vision: 0, embedding: 0, other: 0 };
    96→    this.providerBreakdown = { openai: 0, nim: 0, other: 0 };
    97→    this._updateResetTime();
    98→
    99→    console.log(`[token-budget] Daily reset. New day: ${newDay}. Previous budget ${wasExhausted ? 'was exhausted' : 'had remaining tokens'}.`);
   100→    if (wasExhausted) {
   101→      console.log('[token-budget] OpenAI is now available again after budget reset.');
   102→    }
   103→  }
   104→
   105→  /**
   106→   * Record token usage for an AI call.
   107→   * @param {string} modality - 'llm', 'tts', 'asr', 'vision', 'embedding'
   108→   * @param {number} tokens - Number of tokens used
   109→   * @param {string} [provider] - 'openai', 'nim', etc. (default: 'openai')
   110→   */
   111→  recordUsage(modality, tokens, provider = 'openai') {
   112→    // Check if day rolled over
   113→    const today = this._getUTCDay();
   114→    if (today !== this.currentDay) {
   115→      this._performReset(today);
   116→    }
   117→
   118→    this.tokensUsed += tokens;
   119→    const bucket = this.modalityBreakdown[modality] !== undefined ? modality : 'other';
   120→    this.modalityBreakdown[bucket] += tokens;
   121→    const provBucket = this.providerBreakdown[provider] !== undefined ? provider : 'other';
   122→    this.providerBreakdown[provBucket] += tokens;
   123→
   124→    // Check if budget is now exhausted
   125→    if (!this.budgetExhausted && this.tokensUsed >= this.dailyBudget) {
   126→      this.budgetExhausted = true;
   127→      this.exhaustedAt = new Date().toISOString();
   128→      console.log(`[token-budget] BUDGET EXHAUSTED at ${this.tokensUsed.toLocaleString()} tokens. Routing to NIM providers.`);
   129→      // Log to activity feed
   130→      try {
   131→        const { logBudgetExhausted } = require('./activity-logger');
   132→        logBudgetExhausted(this.tokensUsed, this.dailyBudget);
   133→      } catch (e) { /* activity logger not loaded yet */ }
   134→    }
   135→  }
   136→
   137→  /**
   138→   * Check if OpenAI should be skipped due to budget exhaustion.
